solution: ```class Solution {
public:
    string longestPalindrome(string s) {
        if (s.empty()) return "";
        int n = s.size(), start = 0, maxLen = 1;
        for (int i = 0; i < n; ++i) {
            int l = i, r = i;
            while (r + 1 < n && s[r] == s[r + 1]) ++r;
            i = r;
            while (l - 1 >= 0 && r + 1 < n && s[l - 1] == s[r + 1]) {
                --l;
                ++r;
            }
            if (r - l + 1 > maxLen) {
                maxLen = r - l + 1;
                start = l;
            }
        }
        return s.substr(start, maxLen);
    }
};
